import torch
from transformers import GPT2LMHeadModel
model = GPT2LMHeadModel.from_pretrained('gpt2', output_hidden_states=True)
model.eval()
def test_hook(module, input, output):
    print(f'Output type: {type(output)}')
    if isinstance(output, tuple):
        print(f'Tuple len: {len(output)}')
        for i, o in enumerate(output):
            if hasattr(o, 'shape'):
                print(f'  [{i}]: {type(o).__name__}, shape={o.shape}')
            elif o is None:
                print(f'  [{i}]: None')
            else:
                print(f'  [{i}]: {type(o).__name__}')
    else:
        print(f'Non-tuple: {type(output).__name__}')

hook = model.transformer.h[0].register_forward_hook(test_hook)
out = model(torch.tensor([[1,2,3]]))
